        serviceHost.Credentials.ServiceCertificate.Certificate = serviceCertificate;
        serviceHost.Credentials.ClientCertificate.Authentication.CertificateValidationMode = 
            X509CertificateValidationMode.PeerOrChainTrust;
        serviceHost.Credentials.ClientCertificate.Authentication.RevocationMode = 
            X509RevocationMode.Online;

        var serviceBehavior = serviceHost.Description.Behaviors.Find<ServiceMetadataBehavior>();
        if (serviceBehavior == null)
        {
            serviceBehavior = new ServiceMetadataBehavior();
            serviceHost.Description.Behaviors.Add(serviceBehavior);
        }
        serviceBehavior.HttpsGetEnabled = true;

        var debugBehavior = serviceHost.Description.Behaviors.Find<ServiceDebugBehavior>();
        if (debugBehavior == null)
        {
            debugBehavior = new ServiceDebugBehavior();
            serviceHost.Description.Behaviors.Add(debugBehavior);
        }
        debugBehavior.IncludeExceptionDetailInFaults = false;

        foreach (var endpoint in serviceHost.Description.Endpoints)
        {
            foreach (var operation in endpoint.Contract.Operations)
            {
                var dataContractBehavior = operation.Behaviors.Find<DataContractSerializerOperationBehavior>();
                if (dataContractBehavior != null)
                {
                    dataContractBehavior.MaxItemsInObjectGraph = int.MaxValue;
                }
            }
        }

        serviceHost.Open();
        Console.WriteLine($"Healthcare Records Service started at {serviceUrl}");
        Console.WriteLine("Service is secured with WS-Security and X.509 certificates");
    }

    public void StopService()
    {
        if (serviceHost != null)
        {
            serviceHost.Close();
            Console.WriteLine("Healthcare Records Service stopped");
        }
    }
}

