public class CertificateManager
{
    public static X509Certificate2 LoadCertificate(StoreName storeName, StoreLocation storeLocation, string thumbprint)
    {
        X509Store store = new X509Store(storeName, storeLocation);
        try
        {
            store.Open(OpenFlags.ReadOnly);
            var certificates = store.Certificates.Find(X509FindType.FindByThumbprint, thumbprint, false);
            
            if (certificates.Count == 0)
            {
                throw new Exception($"Certificate with thumbprint {thumbprint} not found");
            }
            
            return certificates[0];
        }
        finally
        {
            store.Close();
        }
    }

    public static X509Certificate2 CreateSelfSignedCertificate(string subjectName)
    {
        var distinguishedName = new System.Security.Cryptography.X509Certificates.X500DistinguishedName($"CN={subjectName}");
        
        using (var rsa = System.Security.Cryptography.RSA.Create(2048))
        {
            var request = new System.Security.Cryptography.X509Certificates.CertificateRequest(
                distinguishedName, 
                rsa, 
                System.Security.Cryptography.HashAlgorithmName.SHA256,
                System.Security.Cryptography.RSASignaturePadding.Pkcs1);

            request.CertificateExtensions.Add(
                new System.Security.Cryptography.X509Certificates.X509KeyUsageExtension(
                    System.Security.Cryptography.X509Certificates.X509KeyUsageFlags.DataEncipherment | 
                    System.Security.Cryptography.X509Certificates.X509KeyUsageFlags.KeyEncipherment | 
                    System.Security.Cryptography.X509Certificates.X509KeyUsageFlags.DigitalSignature, 
                    false));

            request.CertificateExtensions.Add(
                new System.Security.Cryptography.X509Certificates.X509EnhancedKeyUsageExtension(
                    new System.Security.Cryptography.OidCollection 
                    { 
                        new System.Security.Cryptography.Oid("1.3.6.1.5.5.7.3.1"),
                        new System.Security.Cryptography.Oid("1.3.6.1.5.5.7.3.2")
                    }, 
                    false));

            var certificate = request.CreateSelfSigned(
                DateTimeOffset.Now, 
                DateTimeOffset.Now.AddYears(5));

            return new X509Certificate2(
                certificate.Export(X509ContentType.Pfx, "password"), 
                "password", 
                X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.PersistKeySet | X509KeyStorageFlags.Exportable);
        }
    }
}

public class Program
{
    public static void Main(string[] args)
    {
        Console.WriteLine("HIPAA-Compliant Healthcare Records Service");
        Console.WriteLine("=========================================");

        try
        {
            var serverCert = CertificateManager.CreateSelfSignedCertificate("HealthcareServiceServer");
            var clientCert = CertificateManager.CreateSelfSignedCertificate("HealthcareServiceClient");

            var hostConfig = new ServiceHostConfiguration();
            hostConfig.StartService("https://localhost:8443/HealthcareRecords", serverCert);

            Console.WriteLine("\nPress Enter to test the service...");
            Console.ReadLine();

            using (var client = new HealthcareServiceClient(
                "https://localhost:8443/HealthcareRecords", 
                clientCert, 
                serverCert))
            {
                var patient = new Patient
                {
                    FirstName = "John",
                    LastName = "Doe",
                    DateOfBirth = new DateTime(1980, 5, 15),
                    SSN = "123-45-6789",
                    Address = "123 Main St, City, State 12345",
                    Phone = "555-1234",
                    Email = "john.doe@email.com"
                };

                var addResponse = client.AddPatient(patient);
                Console.WriteLine($"\nAdd Patient: {addResponse.Message} - ID: {addResponse.RecordId}");

                var retrievedPatient = client.GetPatient(addResponse.RecordId);
                if (retrievedPatient != null)
                {
                    Console.WriteLine($"Retrieved Patient: {retrievedPatient.FirstName} {retrievedPatient.LastName}");
                }

                var medicalRecord = new MedicalRecord
                {
                    PatientId = addResponse.RecordId,
                    RecordDate = DateTime.UtcNow,
                    Diagnosis = "Hypertension",
                    Treatment = "Lifestyle modification and medication",
                    Medications = "Lisinopril 10mg daily",
                    PhysicianNotes = "Patient advised to reduce sodium intake",
                    Allergies = new List<string> { "Penicillin" },
                    LabResults = "BP: 140/90"
                };

                var recordResponse = client.AddMedicalRecord(medicalRecord);
                Console.WriteLine($"\nAdd Medical Record: {recordResponse.Message} - ID: {recordResponse.RecordId}");

                var prescription = new Prescription
                {
                    PatientId = addResponse.RecordId,
                    MedicationName = "Lisinopril",
                    Dosage = "10mg",
                    Frequency = "Once daily",
                    PrescribedDate = DateTime.UtcNow,
                    ExpirationDate = DateTime.UtcNow.AddMonths(6),
                    PhysicianName = "Dr. Smith"
                };

                var prescriptionResponse = client.AddPrescription(prescription);
                Console.WriteLine($"\nAdd Prescription: {prescriptionResponse.Message} - ID: {prescriptionResponse.RecordId}");

                var history = client.GetPatientMedicalHistory(addResponse.RecordId);
                Console.WriteLine($"\nMedical History Count: {history.Count}");

                var prescriptions = client.GetPatientPrescriptions(addResponse.RecordId);
                Console.WriteLine($"Prescriptions Count: {prescriptions.Count}");
            }

            Console.WriteLine("\nPress Enter to stop the service...");
            Console.ReadLine();

            hostConfig.StopService();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
            Console.WriteLine($"Stack Trace: {ex.StackTrace}");
        }

        Console.WriteLine("\nPress Enter to exit...");
        Console.ReadLine();
    }
}